/**
 * Parse an octal string from a buffer.
 * Leading spaces are ignored.
 * The buffer must contain a trailing space or NUL,
 * and may contain an additional trailing space or NUL.
 *
 * The input buffer is allowed to contain all NULs,
 * in which case the method returns 0L
 * (this allows for missing fields).
 *
 * @param buffer The buffer from which to parse.
 * @param offset The offset into the buffer from which to parse.
 * @param length The maximum number of bytes to parse - must be at least 2 bytes.
 * @return The long value of the octal string.
 * @throws IllegalArgumentException if the trailing space/NUL is missing or if a invalid byte is detected.
 */
public static long parseOctal(final byte[] buffer, final int offset, final int length) {
    if (length < 2) {
        throw new IllegalArgumentException("Length cannot be less than 2");
    }

    // Check if the buffer contains all NULs - this should return 0
    boolean allNuls = true;
    for (int j = offset; j < offset + length; j++) {
        if (buffer[j] != 0) {
            allNuls = false;
            break;
        }
    }
    if (allNuls) {
        return 0L;
    }

    long    result = 0;
    boolean stillPadding = true;
    int     end = offset + length;
    int     start = offset;

    for (int i = start; i < end; i++){
        final byte currentByte = buffer[i];
        if (currentByte == 0) {
            // NUL terminates the number, everything after should be trailers
            for (int j = i + 1; j < end; j++) {
                if (buffer[j] != ' ' && buffer[j] != 0) {
                    throw new IllegalArgumentException(
                            exceptionMessage(buffer, offset, length, j, buffer[j]));
                }
            }
            return result;
        }

        // Handle spaces and zeros
        if (currentByte == (byte) ' ' || currentByte == '0') {
            if (stillPadding) {
                // Still in leading padding phase, skip
                continue;
            } else {
                // We're past the padding phase, this space should terminate the number
                // Check that everything after is trailers
                for (int j = i + 1; j < end; j++) {
                    if (buffer[j] != ' ' && buffer[j] != 0) {
                        throw new IllegalArgumentException(
                                exceptionMessage(buffer, offset, length, j, buffer[j]));
                    }
                }
                return result;
            }
        }

        // Now processing digits (this is where stillPadding becomes false for the first time)
        stillPadding = false;
        // CheckStyle:MagicNumber OFF
        if (currentByte < '0' || currentByte > '7'){
            throw new IllegalArgumentException(
                    exceptionMessage(buffer, offset, length, i, currentByte));
        }
        result = (result << 3) + (currentByte - '0'); // convert from ASCII
        // CheckStyle:MagicNumber ON
    }

    // If we got here without hitting a terminator, and we read digits, it's an error
    if (!stillPadding) {
        throw new IllegalArgumentException(
            "Number not properly terminated with space or NUL: " + new String(buffer, offset, length));
    }

    return result;
}

